发现一篇整理的不错的，常用JS函数，支持下作者。


作者github，start

常用函数汇总1.Array1.1 arrayEqual/** *  * @desc 判断两个数组是否相等 * @param &#123;Array&#125; arr1  * @param &#123;Array&#125; arr2  * @return &#123;Boolean&#125; */function arrayEqual(arr1, arr2) &#123;    if (arr1 === arr2) return true;    if (arr1.length != arr2.length) return false;    for (var i = 0; i &lt; arr1.length; ++i) &#123;        if (arr1[i] !== arr2[i]) return false;    &#125;    return true;&#125;

2.Class2.1 addClass/** *  * @desc   为元素添加class * @param  &#123;HTMLElement&#125; ele  * @param  &#123;String&#125; cls  */var hasClass = require(&#x27;./hasClass&#x27;);function addClass(ele, cls) &#123;    if (!hasClass(ele, cls)) &#123;        ele.className += &#x27; &#x27; + cls;    &#125;&#125;

2.2 hasClass/** *  * @desc 判断元素是否有某个class * @param &#123;HTMLElement&#125; ele  * @param &#123;String&#125; cls  * @return &#123;Boolean&#125; */function hasClass(ele, cls) &#123;    return (new RegExp(&#x27;(\\s|^)&#x27; + cls + &#x27;(\\s|$)&#x27;)).test(ele.className);&#125;

2.3 removeClass/** *  * @desc 为元素移除class * @param &#123;HTMLElement&#125; ele  * @param &#123;String&#125; cls  */var hasClass = require(&#x27;./hasClass&#x27;);function removeClass(ele, cls) &#123;    if (hasClass(ele, cls)) &#123;        var reg = new RegExp(&#x27;(\\s|^)&#x27; + cls + &#x27;(\\s|$)&#x27;);        ele.className = ele.className.replace(reg, &#x27; &#x27;);    &#125;&#125;

3.Cookie3.1 getCookie/** *  * @desc 根据name读取cookie * @param  &#123;String&#125; name  * @return &#123;String&#125; */function getCookie(name) &#123;    var arr = document.cookie.replace(/\s/g, &quot;&quot;).split(&#x27;;&#x27;);    for (var i = 0; i &lt; arr.length; i++) &#123;        var tempArr = arr[i].split(&#x27;=&#x27;);        if (tempArr[0] == name) &#123;            return decodeURIComponent(tempArr[1]);        &#125;    &#125;    return &#x27;&#x27;;&#125;

3.2 removeCookievar setCookie = require(&#x27;./setCookie&#x27;);/** *  * @desc 根据name删除cookie * @param  &#123;String&#125; name  */function removeCookie(name) &#123;    // 设置已过期，系统会立刻删除cookie    setCookie(name, &#x27;1&#x27;, -1);&#125;

3.3 setCookie/** *  * @desc  设置Cookie * @param &#123;String&#125; name  * @param &#123;String&#125; value  * @param &#123;Number&#125; days  */function setCookie(name, value, days) &#123;    var date = new Date();    date.setDate(date.getDate() + days);    document.cookie = name + &#x27;=&#x27; + value + &#x27;;expires=&#x27; + date;&#125;

4.Device4.1 getExplore/** *  * @desc 获取浏览器类型和版本 * @return &#123;String&#125;  */function getExplore() &#123;    var sys = &#123;&#125;,        ua = navigator.userAgent.toLowerCase(),        s;    (s = ua.match(/rv:([\d.]+)\) like gecko/)) ? sys.ie = s[1]:        (s = ua.match(/msie ([\d\.]+)/)) ? sys.ie = s[1] :        (s = ua.match(/edge\/([\d\.]+)/)) ? sys.edge = s[1] :        (s = ua.match(/firefox\/([\d\.]+)/)) ? sys.firefox = s[1] :        (s = ua.match(/(?:opera|opr).([\d\.]+)/)) ? sys.opera = s[1] :        (s = ua.match(/chrome\/([\d\.]+)/)) ? sys.chrome = s[1] :        (s = ua.match(/version\/([\d\.]+).*safari/)) ? sys.safari = s[1] : 0;    // 根据关系进行判断    if (sys.ie) return (&#x27;IE: &#x27; + sys.ie)    if (sys.edge) return (&#x27;EDGE: &#x27; + sys.edge)    if (sys.firefox) return (&#x27;Firefox: &#x27; + sys.firefox)    if (sys.chrome) return (&#x27;Chrome: &#x27; + sys.chrome)    if (sys.opera) return (&#x27;Opera: &#x27; + sys.opera)    if (sys.safari) return (&#x27;Safari: &#x27; + sys.safari)    return &#x27;Unkonwn&#x27;&#125;

