16: &#x27;F5&#x27;,    117: &#x27;F6&#x27;,    118: &#x27;F7&#x27;,    119: &#x27;F8&#x27;,    120: &#x27;F9&#x27;,    121: &#x27;F10&#x27;,    122: &#x27;F11&#x27;,    123: &#x27;F12&#x27;,    144: &#x27;Num Lock&#x27;,    145: &#x27;Scroll Lock&#x27;,    182: &#x27;My Computer&#x27;,    183: &#x27;My Calculator&#x27;,    186: &#x27;;&#x27;,    187: &#x27;=&#x27;,    188: &#x27;,&#x27;,    189: &#x27;-&#x27;,    190: &#x27;.&#x27;,    191: &#x27;/&#x27;,    192: &#x27;`&#x27;,    219: &#x27;[&#x27;,    220: &#x27;\\&#x27;,    221: &#x27;]&#x27;,    222: &#x27;\&#x27;&#x27;&#125;;/** * @desc 根据keycode获得键名 * @param  &#123;Number&#125; keycode  * @return &#123;String&#125; */function getKeyName(keycode) &#123;    if (keyCodeMap[keycode]) &#123;        return keyCodeMap[keycode];    &#125; else &#123;        console.log(&#x27;Unknow Key(Key Code:&#x27; + keycode + &#x27;)&#x27;);        return &#x27;&#x27;;    &#125;&#125;;

7.Object7.1 deepClone/** * @desc 深拷贝，支持常见类型 * @param &#123;Any&#125; values */function deepClone(values) &#123;    var copy;    // Handle the 3 simple types, and null or undefined    if (null == values || &quot;object&quot; != typeof values) return values;    // Handle Date    if (values instanceof Date) &#123;        copy = new Date();        copy.setTime(values.getTime());        return copy;    &#125;    // Handle Array    if (values instanceof Array) &#123;        copy = [];        for (var i = 0, len = values.length; i &lt; len; i++) &#123;            copy[i] = deepClone(values[i]);        &#125;        return copy;    &#125;    // Handle Object    if (values instanceof Object) &#123;        copy = &#123;&#125;;        for (var attr in values) &#123;            if (values.hasOwnProperty(attr)) copy[attr] = deepClone(values[attr]);        &#125;        return copy;    &#125;    throw new Error(&quot;Unable to copy values! Its type isn&#x27;t supported.&quot;);&#125;

