10.String10.1 digitUppercase/** *  * @desc   现金额转大写 * @param  &#123;Number&#125; n  * @return &#123;String&#125; */function digitUppercase(n) &#123;    var fraction = [&#x27;角&#x27;, &#x27;分&#x27;];    var digit = [        &#x27;零&#x27;, &#x27;壹&#x27;, &#x27;贰&#x27;, &#x27;叁&#x27;, &#x27;肆&#x27;,        &#x27;伍&#x27;, &#x27;陆&#x27;, &#x27;柒&#x27;, &#x27;捌&#x27;, &#x27;玖&#x27;    ];    var unit = [        [&#x27;元&#x27;, &#x27;万&#x27;, &#x27;亿&#x27;],        [&#x27;&#x27;, &#x27;拾&#x27;, &#x27;佰&#x27;, &#x27;仟&#x27;]    ];    var head = n &lt; 0 ? &#x27;欠&#x27; : &#x27;&#x27;;    n = Math.abs(n);    var s = &#x27;&#x27;;    for (var i = 0; i &lt; fraction.length; i++) &#123;        s += (digit[Math.floor(n * 10 * Math.pow(10, i)) % 10] + fraction[i]).replace(/零./, &#x27;&#x27;);    &#125;    s = s || &#x27;整&#x27;;    n = Math.floor(n);    for (var i = 0; i &lt; unit[0].length &amp;&amp; n &gt; 0; i++) &#123;        var p = &#x27;&#x27;;        for (var j = 0; j &lt; unit[1].length &amp;&amp; n &gt; 0; j++) &#123;            p = digit[n % 10] + unit[1][j] + p;            n = Math.floor(n / 10);        &#125;        s = p.replace(/(零.)*零$/, &#x27;&#x27;).replace(/^$/, &#x27;零&#x27;) + unit[0][i] + s;    &#125;    return head + s.replace(/(零.)*零元/, &#x27;元&#x27;)        .replace(/(零.)+/g, &#x27;零&#x27;)        .replace(/^整$/, &#x27;零元整&#x27;);&#125;;

