12.Time12.1 formatPassTime/** * @desc   格式化$&#123;startTime&#125;距现在的已过时间 * @param  &#123;Date&#125; startTime  * @return &#123;String&#125; */function formatPassTime(startTime) &#123;    var currentTime = Date.parse(new Date()),        time = currentTime - startTime,        day = parseInt(time / (1000 * 60 * 60 * 24)),        hour = parseInt(time / (1000 * 60 * 60)),        min = parseInt(time / (1000 * 60)),        month = parseInt(day / 30),        year = parseInt(month / 12);    if (year) return year + &quot;年前&quot;    if (month) return month + &quot;个月前&quot;    if (day) return day + &quot;天前&quot;    if (hour) return hour + &quot;小时前&quot;    if (min) return min + &quot;分钟前&quot;    else return &#x27;刚刚&#x27;&#125;

12.2 formatRemainTime/** *  * @desc   格式化现在距$&#123;endTime&#125;的剩余时间 * @param  &#123;Date&#125; endTime   * @return &#123;String&#125; */function formatRemainTime(endTime) &#123;    var startDate = new Date(); //开始时间    var endDate = new Date(endTime); //结束时间    var t = endDate.getTime() - startDate.getTime(); //时间差    var d = 0,        h = 0,        m = 0,        s = 0;    if (t &gt;= 0) &#123;        d = Math.floor(t / 1000 / 3600 / 24);        h = Math.floor(t / 1000 / 60 / 60 % 24);        m = Math.floor(t / 1000 / 60 % 60);        s = Math.floor(t / 1000 % 60);    &#125;    return d + &quot;天 &quot; + h + &quot;小时 &quot; + m + &quot;分钟 &quot; + s + &quot;秒&quot;;&#125;

13.Url13.1 parseQueryString/** *  * @desc   url参数转对象 * @param  &#123;String&#125; url  default: window.location.href * @return &#123;Object&#125;  */function parseQueryString(url) &#123;    url = url == null ? window.location.href : url    var search = url.substring(url.lastIndexOf(&#x27;?&#x27;) + 1)    if (!search) &#123;        return &#123;&#125;    &#125;    return JSON.parse(&#x27;&#123;&quot;&#x27; + decodeURIComponent(search).replace(/&quot;/g, &#x27;\\&quot;&#x27;).replace(/&amp;/g, &#x27;&quot;,&quot;&#x27;).replace(/=/g, &#x27;&quot;:&quot;&#x27;) + &#x27;&quot;&#125;&#x27;)&#125;

13.2 stringfyQueryString/** *  * @desc   对象序列化 * @param  &#123;Object&#125; obj  * @return &#123;String&#125; */function stringfyQueryString(obj) &#123;    if (!obj) return &#x27;&#x27;;    var pairs = [];    for (var key in obj) &#123;        var value = obj[key];        if (value instanceof Array) &#123;            for (var i = 0; i &lt; value.length; ++i) &#123;                pairs.push(encodeURIComponent(key + &#x27;[&#x27; + i + &#x27;]&#x27;) + &#x27;=&#x27; + encodeURIComponent(value[i]));            &#125;            continue;        &#125;        pairs.push(encodeURIComponent(key) + &#x27;=&#x27; + encodeURIComponent(obj[key]));    &#125;    return pairs.join(&#x27;&amp;&#x27;);&#125;

14.Function14.1 throttle/** * @desc   函数节流。 * 适用于限制`resize`和`scroll`等函数的调用频率 * * @param  &#123;Number&#125;    delay          0 或者更大的毫秒数。 对于事件回调，大约100或250毫秒（或更高）的延迟是最有用的。 * @param  &#123;Boolean&#125;   noTrailing     可选，默认为false。 *                                    如果noTrailing为true，当节流函数被调用，每过`delay`毫秒`callback`也将执行一次。 *                                    如果noTrailing为false或者未传入，`callback`将在最后一次调用节流函数后再执行一次. *                                    （延迟`delay`毫秒之后，节流函数没有被调用,内部计数器会复位） * @param  &#123;Function&#125;  callback       延迟毫秒后执行的函数。`this`上下文和所有参数都是按原样传递的， *                                    执行去节流功能时，调用`callback`。 * @param  &#123;Boolean&#125;   debounceMode   如果`debounceMode`为true，`clear`在`delay`ms后执行。 *                                    如果debounceMode是false，`callback`在`delay` ms之后执行。 * * @return &#123;Function&#125;  新的节流函数 */function throttle(delay, noTrailing, callback, debounceMode) &#123;    // After wrapper has stopped being called, this timeout ensures that    // `callback` is executed at the proper times in `throttle` and `end`    // debounce modes.    var timeoutID;    // Keep track of the last time `callback` was executed.    var lastExec = 0;    // `noTrailing` defaults to falsy.    if (typeof noTrailing !== &#x27;boolean&#x27;) &#123;        debounceMode = callback;        callback = noTrailing;        noTrailing = undefined;    &#125;    // The `wrapper` function encapsulates all of the throttling / debouncing    // functionality and when executed will limit the rate at which `callback`    // is executed.    function wrapper() &#123;        var self = this;        var elapsed = Number(new Date()) - lastExec;        var args = arguments;        // Execute `callback` and update the `lastExec` timestamp.        function exec() &#123;            lastExec = Number(new Date());            callback.apply(self, args);        &#125;        // If `debounceMode` is true (at begin) this is used to clear the flag        // to allow future `callback` executions.        function clear() &#123;            timeoutID = undefined;        &#125;        if (debounceMode &amp;&amp; !timeoutID) &#123;            // Since `wrapper` is being called for the first time and            // `debounceMode` is true (at begin), execute `callback`.            exec();        &#125;        // Clear any existing timeout.        if (timeoutID) &#123;            clearTimeout(timeoutID);        &#125;        if (debounceMode === undefined &amp;&amp; elapsed &gt; delay) &#123;            // In throttle mode, if `delay` time has been exceeded, execute            // `callback`.            exec();        &#125; else if (noTrailing !== true) &#123;            // In trailing throttle mode, since `delay` time has not been            // exceeded, schedule `callback` to execute `delay` ms after most            // recent execution.            //            // If `debounceMode` is true (at begin), schedule `clear` to execute            // after `delay` ms.            //            // If `debounceMode` is false (at end), schedule `callback` to            // execute after `delay` ms.            timeoutID = setTimeout(debounceMode ? clear : exec, debounceMode === undefined ? delay - elapsed : delay);        &#125;    &#125;    // Return the wrapper function.    return wrapper;&#125;;

14.2 debounce/** * @desc 函数防抖  * 与throttle不同的是，debounce保证一个函数在多少毫秒内不再被触发，只会执行一次， * 要么在第一次调用return的防抖函数时执行，要么在延迟指定毫秒后调用。 * @example 适用场景：如在线编辑的自动存储防抖。 * @param  &#123;Number&#125;   delay         0或者更大的毫秒数。 对于事件回调，大约100或250毫秒（或更高）的延迟是最有用的。 * @param  &#123;Boolean&#125;  atBegin       可选，默认为false。 *                                  如果`atBegin`为false或未传入，回调函数则在第一次调用return的防抖函数后延迟指定毫秒调用。                                    如果`atBegin`为true，回调函数则在第一次调用return的防抖函数时直接执行 * @param  &#123;Function&#125; callback      延迟毫秒后执行的函数。`this`上下文和所有参数都是按原样传递的， *                                  执行去抖动功能时，，调用`callback`。 * * @return &#123;Function&#125; 新的防抖函数。 */var throttle = require(&#x27;./throttle&#x27;);function debounce(delay, atBegin, callback) &#123;    return callback === undefined ? throttle(delay, atBegin, false) : throttle(delay, callback, atBegin !== false);&#125;;

封装除了对上面这些常用函数进行封装， 最重要的是支持合理化的引入，这里我们使用webpack统一打包成UMD 通用模块规范，支持webpack、RequireJS、SeaJS等模块加载器，亦或直接通过&lt;script&gt;标签引入。
但这样，还是不能让人满意。因为完整引入整个库，略显浪费，我们不可能用到所有的函数。那么，就支持按需引入吧
1.目录结构说明│  .babelrc│  .gitignore│  .travis.yml│  LICENSE│  package.json│  README.md│  setCookie.js  // 拷贝到根路径的函数模块，方便按需加载│  setScrollTop.js│  stringfyQueryString.js│   ...│   ...│  ├─min│      outils.min.js  // 所有函数统一打包生成的全量压缩包│      ├─script  // 本项目开发脚本目录│      build.js  // 打包构建脚本│      test.js  // 测试脚本│      webpack.conf.js  // webpack打包配置文件│      ├─src // 源码目录│  │  index.js  // webpack入口文件│  │  │  ├─array│  │      │  ├─class│  │      │  ├─cookie│  │      │  ├─device│  │      │  ├─dom│  │      │  ├─keycode│  │      │  ├─object│  │      │  ├─random│  │      │  ├─regexp│  │      │  ├─string│  │      │  ├─support│  │      │  ├─time│  │      │  └─url│          └─test // 测试用例目录    │  array.test.js    │  class.test.js    │  cookie.test.js    │  device.test.js    │  dom.test.js    │  index.html    │  keycode.test.js    │  object.test.js    │  random.test.js    │  regexp.test.js    │  string.test.js    │  support.test.js    │  time.test.js    │  url.test.js    │      └─_lib // 测试所用到的第三方库            mocha.css            mocha.js            power-assert.js 

2.构建脚本这里主要说明一下项目中 build.js 的构建过程第一步，构建全量压缩包，先删除min目录中之前的outils.min.js，后通过webpack打包并保存新的压缩包至min目录中：
............// 删除旧的全量压缩包rm(path.resolve(rootPath, &#x27;min&#x27;, `$&#123;pkg.name&#125;.min.js`), err =&gt; &#123;    if (err) throw (err)    webpack(config, function (err, stats) &#123;        if (err) throw (err)        building.stop()        process.stdout.write(stats.toString(&#123;            colors: true,            modules: false,            children: false,            chunks: false,            chunkModules: false        &#125;) + &#x27;\n\n&#x27;)        resolve()        console.log(chalk.cyan(&#x27;  Build complete.\n&#x27;))    &#125;)&#125;)............

第二步，拷贝函数模块至根目录，先删除根目录中之前的函数模块，后拷贝src下面一层目录的所有js文件至根目录。这么做的目的是，拷贝到根路径，在引入的时候，直接require(&#39;outils/&lt;方法名&gt;&#39;)即可，缩短引入的路径，也算是提高点效率。
// 替换模块文件    ......    ......    // 先删除根目录中之前的函数模块    rm(&#x27;*.js&#x27;, err =&gt; &#123;        if (err) throw (err)        let folderList = fs.readdirSync(path.resolve(rootPath, &#x27;src&#x27;))        folderList.forEach((item, index) =&gt; &#123;            // 拷贝`src`下面一层目录的所有`js`文件至根目录            copy(`src/$&#123;item&#125;/*.js`, rootPath, function (err, files) &#123;                if (err) throw err;                if (index === folderList.length - 1) &#123;                    console.log(chalk.cyan(&#x27;  Copy complete.\n&#x27;))                    copying.stop()                &#125;            &#125;)        &#125;)    &#125;)    ......    ......

3.书写测试用例俗话说，不写测试用例的前端不是一个好程序员。那就不能怂，就是干。
但是因为时间关系，本项目暂时通过项目中的 test.js ，启动了一个koa静态服务器，来加载mocha网页端的测试页面，让笔者书写项目时，可以在本地对函数功能进行测试。但是后续将使用travis-ci配合Github来做持续化构建，自动发布到npm。改用karma，mocha，power-assert做单元测试，使用Coverage测试覆盖率。这一部分，后续更新。
这里给大家推荐一个好用的断言库 power-assert ，这个库记住assert(value, [message])一个API就基本无敌，从此再也不用担心记不住断言库的API。
本项目的所有测试用例都在test目录下，大家可以作一定参考。

更新：单元测试，已使用karma，mocha，power-assert，使用Coverage测试覆盖率，并集成 travis-ci 配合Github来做持续化构建，可以参考本项目的travis配置文件 .travis.yml 和karma的配置文件 karma.conf.js 。

发布首先放到Github托管一下，当然你也可以直接fork本项目，然后再加入你自己的函数。以笔者项目，举个栗子:
1.添加自己的函数在src目录下，新建分类目录或者选择一个分类，在子文件夹中添加函数模块文件（建议一个小功能保存为一个JS文件）。
/** *  * @desc   判断是否NaN * @param  &#123;Any&#125; value  * @return &#123;Boolean&#125; */function isNaN(value) &#123;        return value !== value;&#125;;modules.export = isNaN

然后记得在src/index.js文件中暴露isNaN函数
2.单元测试在test文件新建测试用例
describe(&#x27;#isNaN()&#x27;, function () &#123;    it(`outils.isNaN(NaN) should return true`, function () &#123;        assert(outils.isNaN(NaN))    &#125;)    it(`outils.isNaN(&#x27;value&#x27;) should return false`, function () &#123;        assert.notEqual(outils.isNaN(NaN))    &#125;)&#125;)

然后记得在test/index.html中引入之前创建的测试用例脚本。
3.测试并打包执行npm run test，看所有的测试用例是否通过。如果没有问题，执行npm run build构建，之后提交到个人的 github 仓库即可。
4.发布到npm在 www.npmjs.com 注册账号，修改本地package.json中的name、version、author等信息，最后npm publish就大功告成了。注意：向npm发包，要把镜像源切到 www.npmjs.com ，使用cnpm等第三方镜像源会报错。
使用1.浏览器直接下载min目录下的 outils.min.js ，通过&lt;script&gt;标签引入。
&lt;script src=&quot;outils.min.js&quot;&gt;&lt;/script&gt;&lt;script&gt;    var OS = outils.getOS()&lt;/script&gt;

注意： 本仓库代码会持续更新，如果你需要不同版本的增量压缩包或源码，请到 github Release 页面下载对应版本号的代码。
2.Webpack、RequireJS、SeaJS等模块加载器先使用npm安装outils。
$ npm install --save-dev outils

// 完整引入const outils = require(&#x27;outils&#x27;)const OS = outils.getOS()

推荐使用方法
// 按需引入require(&#x27;outils/&lt;方法名&gt;&#x27;)const getOS = require(&#x27;outils/getOS&#x27;)const OS = getOS()

当然，你的开发环境有babel编译ES6语法的话，也可以这样使用：
import getOS from &#x27;outils/getOS&#x27;// 或import &#123; getOS &#125; from &quot;outils&quot;;

总结工欲善其事必先利其器。有了属于自己的这把利器，希望加班也会变成奢望。O(∩_∩)O哈哈~

最近使用vue比较多，项目过程中遇到了，上传图片、视频到阿里云的OSS存储服务，发现目前现成的上传组件，都不太支持，于是自己各种查看阿里云的文档及google，百度，自己写了一套符合自己的业务的上传组件，想到其他小伙伴肯定也会遇到类似的问题，就花了些时间，把组件提取出来，上传到了npm。

基本思路：服务端提供接口，获取阿里云STS临时访问OSS的权限，初始化ossClient，调用oss的sdk进行上传。通过vue2.3重新引入的sync特性返回上传结果
使用组件时，需要导入Css样式。自己不擅长写样式，写的比较挫，希望可以被改进，哈哈

TODO: 上传的进度，等尚未实现，只有最终上传结果




github 地址

vue-oss-uploadNote需要依赖阿里云的oss的SDK,可以在index.html中引入  &lt;script type=&quot;text/javascript&quot; src=&quot;https://gosspublic.alicdn.com/aliyun-oss-sdk.min.js&quot;&gt;&lt;/script&gt;
组件依赖vue2.3以上的版本vue2.3 重新引入了 .sync 修饰符，但是这次它只是作为一个编译时的语法糖存在。它会被扩展为一个自动更新父组件属性的 v-on 侦听器。
.sync 修饰符
Use SetupInstall vue-oss-uploadnpm install vue-oss-upload --save

props props: {
      // 需要引入阿里云OSS的SDK，并初始化ossClient
      ossClient: {
        type: Object,
        toWay: false
      },
      // 是非支持多文件上传
      multiple: {
        type: Boolean,
        twoWay: false
      },
      // 上传组件id，区别页面中多次使用上传组件
      id: {
        type: String,
        twoWay: false
      },
      // 上传成功后的uri
      url: {
        type: String,
        twoWay: true
      },
       // 上传结果
      uploadRes: {
        type: Boolean,
        twoWay: true
      },
      // 上传按钮的名称
      inputName: {
        type: String,
      },
      // 上传文件的名称
      uploadFileName: {
        type: String,
      },
      // 上传到OSS的路径
      path: {
        type: String,
      },
    },

Example&lt;template&gt;
    &lt;div&gt;
        &lt;upload-ali-oss :url.sync=&quot;uploadForm.content.path&quot; :multiple=&quot;true&quot;
                        :id=&quot;uploadForm.id&quot;
                        :ossClient=&quot;this.ossClient&quot;
                        :inputName=&quot;uploadForm.inputName&quot;
						:uploadFileName=&quot;uploadForm.uploadFileName&quot;
                        :path=&quot;uploadForm.upload.path&quot;
                        :uploadRes.sync=&quot;uploadForm.uploadRes&quot;
        &gt;&lt;/upload-ali-oss&gt;
        &lt;div v-show=&quot;uploadForm.uploadRes&quot;
             v-text=&quot;uploadForm.content.path&quot;&gt;
        &lt;/div&gt;
        &lt;div&gt;
            &lt;img src=&quot;/posts/49631/undefined&quot; &gt;
        &lt;/div&gt;
    &lt;/div&gt;
&lt;/template&gt;

&lt;script&gt;
    import VueUploadAliOSS from &#39;vue-oss-upload&#39;;
    import Css from &#39;vue-oss-upload/dist/vue-alioss-upload.min.css&#39;
    export default {
        name: &#39;app&#39;,
        components: {
            &#39;upload-ali-oss&#39;: VueUploadAliOSS
        },
        data() {
            return {
                ossClient: Object,
                uploadForm: {
                    id: &#39;imgFile&#39;,
                    inputName: &#39;上传图片&#39;,// 自定义
					uploadFileName: &#39;2017063010192023&#39;,// 上传文件的名称
                    content: {
                        path: &#39;&#39;,
                    },
                    upload: {
                        path: &#39;img/test/&#39;,// 自定义路径
                    },
                    uploadRes: false,
                },
                imgSrc: &#39;&#39;
            }
        },
        methods: {
            // 需要引入阿里云的ossSDK
            //初始化OSS 权限, 建议后台提供获取oss临时权限的接口
            initOSSAuth() {

                let Oss = OSS.Wrapper;
                this.ossClient = new Oss({
                    region: &#39;&#39;,
                    accessKeyId: &#39;&#39;,
                    accessKeySecret: &#39;&#39;,
                    stsToken: &#39;&#39;,
                    bucket: &#39;&#39;,
                    endpoint: &#39;&#39;,
                });
            },
            // 展示上传的内容（图片）
            showUploadContent() {
                if (this.uploadForm.content.path) {

                    let path = this.uploadForm.content.path;

                    var result = this.ossClient.signatureUrl(path, {
                        response: {
                            // &#39;content-disposition&#39;: &#39;attachment; filename=&quot;&#39; + filename + &#39;&quot;&#39;
                            &#39;Content-Type&#39;: &#39;image/jpeg&#39;
                        }
                    });
                    this.imgSrc = result;
                }
            }
        },
        watch: {
            &#39;uploadForm.content.path&#39; (val, oldVal) {
//                console.log(&#39;new: %s, old: %s&#39;, val, oldVal)
                if (&#39;&#39; !== val) {
                    this.showUploadContent();
                }
            }
        },
        mounted() {
            this.initOSSAuth();
        }
    }
&lt;/script&gt;
